// src/components/BookPage.jsx
//
// All visual properties are driven by `page.style`.
// See pages.js for the full style object reference.

export default function BookPage({ page, pageNum, total, onShowRef, pageW, pageH }) {
  const isCover = page.type === "cover";
  const isEnd   = page.type === "end";

  // ─── scale helper ──────────────────────────────────────────────────────────
  const scale = Math.min(pageW / 380, pageH / 500, 1.6);
  const em = (base) => Math.round(base * scale);

  // ─── unpack style with defaults ────────────────────────────────────────────
  const s = page.style || {};

  const fontFamily      = s.fontFamily      || "'Bubblegum Sans', cursive";
  const titleFontFamily = s.titleFontFamily || fontFamily;
  const textFontFamily  = s.textFontFamily  || fontFamily;

  const titleAlign  = s.titleAlign  || "center";
  const textAlign   = s.textAlign   || "center";
  const titleWeight = s.titleWeight !== undefined ? s.titleWeight : 800;
  const titleItalic = s.titleItalic || false;

  const gap         = s.gap     !== undefined ? s.gap     : 12;
  const [pV, pH]    = s.padding || [24, 20];

  const imageSize   = s.imageSize   !== undefined ? s.imageSize : (isCover || isEnd ? 180 : 140);
  const imageRadius = s.imageRadius !== undefined ? s.imageRadius : 0;
  const imageBorder = s.imageBorder || "none";
  const imageShadow = s.imageShadow !== undefined
    ? s.imageShadow
    : "0 4px 12px rgba(0,0,0,0.15)";
  const imageFit    = s.imageFit    || "contain";

  const cardBg     = s.cardBg     || "rgba(255,255,255,0.28)";
  const cardRadius = s.cardRadius !== undefined ? s.cardRadius : 18;
  const cardBorder = s.cardBorder || "none";
  const [cV, cH]   = s.cardPadding || [14, 18];

  const factsBg     = s.factsBg     || "rgba(255,255,255,0.25)";
  const factsRadius = s.factsRadius !== undefined ? s.factsRadius : 14;
  const factsBorder = s.factsBorder || "none";

  const pageBorder      = s.pageBorder      || "none";
  const overlayCircles  = s.overlayCircles  !== false;   // default true

  // ─── content order ─────────────────────────────────────────────────────────
  const defaultOrder = ["image", "title", "subtitle", "text", "facts", "emoji"];
  const contentOrder = s.contentOrder || defaultOrder;

  // ─── block renderers ───────────────────────────────────────────────────────
  const blocks = {
    image: page.image ? (
      <img
        key="image"
        src={page.image}
        alt={page.title}
        style={{
          width: em(imageSize),
          maxWidth: "80%",
          height: "auto",
          objectFit: imageFit,
          borderRadius: em(imageRadius),
          border: imageBorder,
          filter: `drop-shadow(${imageShadow})`,
          marginBottom: em(gap),
          flexShrink: 0,
        }}
      />
    ) : (
      <div
        key="image"
        style={{
          fontSize: em(isCover || isEnd ? 88 : 68),
          lineHeight: 1,
          marginBottom: em(gap),
        }}
      >
        {page.emoji || "📖"}
      </div>
    ),

    title: (
      <div
        key="title"
        style={{
          fontFamily: titleFontFamily,
          fontSize: em(page.titleSize || (isCover || isEnd ? page.fontSize || 32 : 24)),
          fontWeight: titleWeight,
          fontStyle: titleItalic ? "italic" : "normal",
          textAlign: titleAlign,
          lineHeight: 1.2,
          marginBottom: em(gap),
          textShadow: "0 2px 10px rgba(0,0,0,0.18)",
          letterSpacing: isCover ? "0.04em" : "0.01em",
          width: "100%",
        }}
      >
        {page.title}
      </div>
    ),

    subtitle: page.subtitle ? (
      <div
        key="subtitle"
        style={{
          fontFamily,
          fontSize: em(17),
          opacity: 0.92,
          textAlign: titleAlign,
          marginBottom: em(gap),
          fontStyle: "italic",
          width: "100%",
        }}
      >
        {page.subtitle}
      </div>
    ) : null,

    text: page.text ? (
      <div
        key="text"
        style={{
          fontFamily: textFontFamily,
          fontSize: em(page.fontSize || 17),
          textAlign,
          lineHeight: 1.75,
          maxWidth: em(320),
          width: "100%",
          background: cardBg,
          borderRadius: em(cardRadius),
          border: cardBorder,
          padding: `${em(cV)}px ${em(cH)}px`,
          backdropFilter: "blur(4px)",
          boxSizing: "border-box",
          marginBottom: em(gap),
        }}
      >
        {page.text}
      </div>
    ) : null,

    facts: page.reference?.facts?.length > 0 ? (
      <div
        key="facts"
        style={{
          fontFamily: textFontFamily,
          background: factsBg,
          borderRadius: em(factsRadius),
          border: factsBorder,
          padding: em(14),
          width: "90%",
          maxWidth: em(330),
          backdropFilter: "blur(4px)",
          boxSizing: "border-box",
          marginBottom: em(gap),
        }}
      >
        <h3
          style={{
            margin: `0 0 ${em(10)}px 0`,
            textAlign: "center",
            fontSize: em(16),
            fontFamily: titleFontFamily,
          }}
        >
          📚 Did You Know?
        </h3>
        <ul
          style={{
            margin: 0,
            paddingLeft: em(18),
            fontSize: em(13),
            lineHeight: 1.6,
          }}
        >
          {page.reference.facts.map((fact, i) => (
            <li key={i} style={{ marginBottom: em(6) }}>
              {fact}
            </li>
          ))}
        </ul>
        {page.reference.learnMore && (
          <div style={{ marginTop: em(10), textAlign: "center" }}>
            <a
              href={page.reference.learnMore}
              target="_blank"
              rel="noreferrer"
              style={{
                color: page.textColor || "#333",
                fontWeight: "bold",
                textDecoration: "underline",
              }}
            >
              Learn More →
            </a>
          </div>
        )}
      </div>
    ) : null,

    emoji: page.emoji ? (
      <div
        key="emoji"
        style={{ fontSize: em(42), marginBottom: em(gap) }}
      >
        {page.emoji}
      </div>
    ) : null,
  };

  // ─── render ────────────────────────────────────────────────────────────────
  return (
    <div
      style={{
        width: "100%",
        height: "100%",
        background: page.bg || "#fff",
        color: page.textColor || "#333",
        border: pageBorder,
        display: "flex",
        flexDirection: "column",
        alignItems: "center",
        justifyContent: "center",
        padding: `${em(pV)}px ${em(pH)}px`,
        boxSizing: "border-box",
        fontFamily,
        position: "relative",
        overflowY: "auto",
        overflowX: "hidden",
        userSelect: "none",
      }}
    >
      {/* ── Decorative corner circles (toggleable) ── */}
      {overlayCircles && (
        <>
          <div
            style={{
              position: "absolute",
              top: em(-45),
              left: em(-45),
              width: em(140),
              height: em(140),
              borderRadius: "50%",
              background: "rgba(255,255,255,0.13)",
              pointerEvents: "none",
            }}
          />
          <div
            style={{
              position: "absolute",
              bottom: em(-30),
              right: em(-30),
              width: em(100),
              height: em(100),
              borderRadius: "50%",
              background: "rgba(255,255,255,0.10)",
              pointerEvents: "none",
            }}
          />
        </>
      )}

      {/* ── Learn button ── */}
      {page.reference && (
        <button
          onClick={() => onShowRef?.(page.reference)}
          style={{
            position: "absolute",
            top: em(10),
            left: em(10),
            background: "rgba(255,255,255,0.28)",
            border: "1px solid rgba(255,255,255,0.55)",
            borderRadius: em(20),
            padding: `${em(4)}px ${em(10)}px`,
            cursor: "pointer",
            fontSize: em(12),
            fontWeight: 700,
            color: page.textColor || "#333",
            backdropFilter: "blur(4px)",
            boxShadow: "0 2px 8px rgba(0,0,0,0.1)",
            fontFamily,
          }}
        >
          🔍 Learn
        </button>
      )}

      {/* ── Stars (cover / end only) ── */}
      {(isCover || isEnd) && (
        <div
          style={{
            position: "absolute",
            top: em(10),
            right: em(10),
            fontSize: em(22),
            opacity: 0.75,
            letterSpacing: em(4),
          }}
        >
          ⭐🌟⭐
        </div>
      )}

      {/* ── Ordered content blocks ── */}
      {contentOrder.map((token) => blocks[token] ?? null)}

      {/* ── Page number ── */}
      {!isCover && (
        <div
          style={{
            position: "absolute",
            bottom: em(10),
            fontSize: em(12),
            opacity: 0.55,
            fontFamily: "'Nunito', sans-serif",
          }}
        >
          {pageNum} / {total}
        </div>
      )}
    </div>
  );
}
